import logging
import json
import datetime
import traceback
import os
import threading

class JSONFormatter(logging.Formatter):
    def __init__(self, fmt=None, datefmt=None, style='%', json_indent=None, **kwargs):
        super().__init__(fmt, datefmt, style, **kwargs)
        self.json_indent = json_indent
        self._skip_attributes = {
            'name', 'levelname', 'pathname', 'filename', 'module', 'lineno',
            'funcName', 'created', 'asctime', 'msecs', 'relativeCreated',
            'thread', 'threadName', 'process', 'processName', 'message',
            'args', 'exc_info', 'exc_text', 'stack_info', 'levelno', 'msg'
        }

    def default_json_serializer(self, obj):
        if isinstance(obj, (datetime.datetime, datetime.date, datetime.time)):
            return obj.isoformat()
        if isinstance(obj, bytes):
            return obj.decode('utf-8', errors='replace')
        raise TypeError(f"Object of type {obj.__class__.__name__} is not JSON serializable")

    def format(self, record):
        log_entry = {}

        log_entry['timestamp'] = self.formatTime(record, self.datefmt)
        log_entry['level'] = record.levelname
        log_entry['logger'] = record.name

        message = record.getMessage()
        if isinstance(record.msg, dict) and not record.args:
            log_entry.update(record.msg)
            if 'message' not in log_entry:
                log_entry['message'] = message
        else:
            log_entry['message'] = message

        if record.filename:
            log_entry['source_file'] = record.filename
            log_entry['line_number'] = record.lineno
            log_entry['function_name'] = record.funcName

        if record.exc_info:
            log_entry['exception'] = self.formatException(record.exc_info)
        if record.exc_text:
            log_entry['exception_traceback'] = record.exc_text

        if record.stack_info:
            log_entry['stack_trace'] = self.formatStack(record.stack_info)

        for key, value in record.__dict__.items():
            if key not in self._skip_attributes and not key.startswith('_'):
                try:
                    json.dumps(value, default=self.default_json_serializer)
                    log_entry[key] = value
                except TypeError:
                    log_entry[key] = str(value)

        return json.dumps(log_entry, indent=self.json_indent, default=self.default_json_serializer)


logger = logging.getLogger("my_app")
logger.setLevel(logging.DEBUG)

handler = logging.StreamHandler()

formatter = JSONFormatter(datefmt="%Y-%m-%dT%H:%M:%S%z", json_indent=2)
handler.setFormatter(formatter)

logger.addHandler(handler)

# --- Demonstrations ---

# 1. Basic informational log
logger.info("Application started successfully.")

# 2. Log with custom fields using 'extra'
user_id = "user-abc-123"
logger.warning("Failed to load user profile.", extra={"user_id": user_id, "attempt_count": 3})

# 3. Log with a dictionary as the main message
logger.info({
    "event": "user_activity",
    "action": "login",
    "user_id": "user-def-456",
    "ip_address": "192.168.1.100",
    "status": "success"
})

# 4. Error log with an exception
try:
    result = 10 / 0
except ZeroDivisionError:
    logger.exception("Division by zero occurred.", extra={"operation": "calculate_ratio", "inputs": {"numerator": 10, "denominator": 0}})

# 5. Debug log with process/thread info (often useful for tracing)
logger.debug("Processing task.", extra={
    "task_id": "task-001",
    "worker_id": "worker-A",
    "pid": os.getpid(),
    "thread_name": threading.current_thread().name
})

# 6. Log with a non-JSON serializable object (will be converted to string)
class MyObject:
    def __str__(self):
        return "CustomObject(id=XYZ)"
my_obj_instance = MyObject()
logger.info("Handling custom object.", extra={"object_data": my_obj_instance, "some_date": datetime.datetime.now()})

# 7. Log from a different logger within the same application
logger_api = logging.getLogger("my_app.api_service")
logger_api.addHandler(handler)
logger_api.info("API request received.", extra={"method": "GET", "path": "/users/1", "client_ip": "203.0.113.45"})
logger_api.error("Database connection error.", extra={"service": "api_service", "error_code": 5003})
